#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
struct matrix
{
    long long a[3][3];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    void init()
    {
        a[1][1]=a[2][2]=1;
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(int i=1;i<=2;i++)
        {
            for(int j=1;j<=2;j++)
            {
                for(int k=1;k<=2;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%mod)*(b.a[k][j]%mod)%mod;
                    c.a[i][j]%=mod;
                }
            }
        }
        return c;
    }
}ans,base;
void fastpow(long long y)
{
    ans.a[1][1]=1;
    ans.a[1][2]=1;
    while(y!=0)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    long long n;
    scanf("%lld",&n);
    base.a[1][1]=1;
    base.a[1][2]=1;
    base.a[2][1]=1;
    fastpow(n-2);
    printf("%lld",ans.a[1][1]);
    return 0;
}
